{
  "$schema": "https://json.schemastore.org/claude-code-settings.json",
  "paiVersion": "2.5",
  "env": {
    "PAI_DIR": "C:\\Users\\JOSE\\.claude",
    "PROJECTS_DIR": "C:\\Users\\JOSE\\Projects",
    "CLAUDE_CODE_MAX_OUTPUT_TOKENS": "80000",
    "BASH_DEFAULT_TIMEOUT_MS": "600000"
  },
  "contextFiles": [
    "skills/PAI/SKILL.md",
    "skills/PAI/SYSTEM/AISTEERINGRULES.md",
    "skills/PAI/USER/AISTEERINGRULES.md",
    "skills/PAI/USER/DAIDENTITY.md"
  ],
  "daidentity": {
    "name": "Orion",
    "fullName": "Orion - Personal AI",
    "displayName": "Orion",
    "color": "#3B82F6",
    "voiceId": "pNInz6obpgDQGcFmaJgB",
    "voice": {
      "stability": 0.35,
      "similarity_boost": 0.8,
      "style": 0.9,
      "speed": 1.1,
      "use_speaker_boost": true,
      "volume": 0.8
    },
    "startupCatchphrase": "Orion here, ready to go."
  },
  "principal": {
    "name": "Alfredo",
    "timezone": "America/Sao_Paulo"
  },
  "pai": {
    "repoUrl": "github.com/danielmiessler/PAI",
    "version": "2.5"
  },
  "techStack": {
    "browser": "arc",
    "terminal": "windows-terminal",
    "packageManager": "bun",
    "pythonPackageManager": "pip",
    "language": "TypeScript",
    "devServerPort": 5173
  },
  "permissions": {
    "allow": [
      "Bash",
      "Read",
      "Write",
      "Edit",
      "MultiEdit",
      "Glob",
      "Grep",
      "LS",
      "WebFetch",
      "WebSearch",
      "NotebookRead",
      "NotebookEdit",
      "TodoWrite",
      "ExitPlanMode",
      "Task",
      "Skill",
      "mcp__*"
    ],
    "deny": [],
    "ask": [
      "Bash(rm -rf /)",
      "Bash(rm -rf /:*)",
      "Bash(sudo rm -rf /)",
      "Bash(sudo rm -rf /:*)",
      "Bash(rm -rf ~)",
      "Bash(rm -rf ~:*)",
      "Bash(rm -rf ~/.claude)",
      "Bash(rm -rf ~/.claude:*)",
      "Bash(diskutil eraseDisk:*)",
      "Bash(diskutil zeroDisk:*)",
      "Bash(diskutil partitionDisk:*)",
      "Bash(diskutil apfs deleteContainer:*)",
      "Bash(diskutil apfs eraseVolume:*)",
      "Bash(dd if=/dev/zero:*)",
      "Bash(mkfs:*)",
      "Bash(gh repo delete:*)",
      "Bash(gh repo edit --visibility public:*)",
      "Bash(git push --force:*)",
      "Bash(git push -f:*)",
      "Bash(git push origin --force:*)",
      "Bash(git push origin -f:*)",
      "Read(~/.ssh/id_*)",
      "Read(~/.ssh/*.pem)",
      "Read(~/.aws/credentials)",
      "Read(~/.gnupg/private*)",
      "Write(~/.claude/settings.json)",
      "Edit(~/.claude/settings.json)",
      "Write(~/.ssh/*)",
      "Edit(~/.ssh/*)"
    ],
    "defaultMode": "default"
  },
  "enableAllProjectMcpServers": true,
  "enabledMcpjsonServers": [],
  "hooks": {
    "PreToolUse": [
      {
        "matcher": "Bash",
        "hooks": [
          {
            "type": "command",
            "command": "C:\\Users\\JOSE\\.claude\\hooks\\SecurityValidator.hook.ts"
          }
        ]
      },
      {
        "matcher": "Edit",
        "hooks": [
          {
            "type": "command",
            "command": "C:\\Users\\JOSE\\.claude\\hooks\\SecurityValidator.hook.ts"
          }
        ]
      },
      {
        "matcher": "Write",
        "hooks": [
          {
            "type": "command",
            "command": "C:\\Users\\JOSE\\.claude\\hooks\\SecurityValidator.hook.ts"
          }
        ]
      },
      {
        "matcher": "Read",
        "hooks": [
          {
            "type": "command",
            "command": "C:\\Users\\JOSE\\.claude\\hooks\\SecurityValidator.hook.ts"
          }
        ]
      },
      {
        "matcher": "AskUserQuestion",
        "hooks": [
          {
            "type": "command",
            "command": "C:\\Users\\JOSE\\.claude\\hooks\\SetQuestionTab.hook.ts"
          }
        ]
      }
    ],
    "PostToolUse": [
      {
        "matcher": "AskUserQuestion",
        "hooks": [
          {
            "type": "command",
            "command": "C:\\Users\\JOSE\\.claude\\hooks\\QuestionAnswered.hook.ts"
          }
        ]
      }
    ],
    "SessionEnd": [
      {
        "hooks": [
          {
            "type": "command",
            "command": "C:\\Users\\JOSE\\.claude\\hooks\\WorkCompletionLearning.hook.ts"
          },
          {
            "type": "command",
            "command": "C:\\Users\\JOSE\\.claude\\hooks\\SessionSummary.hook.ts"
          }
        ]
      }
    ],
    "UserPromptSubmit": [
      {
        "hooks": [
          {
            "type": "command",
            "command": "C:\\Users\\JOSE\\.claude\\hooks\\FormatReminder.hook.ts"
          },
          {
            "type": "command",
            "command": "C:\\Users\\JOSE\\.claude\\hooks\\AutoWorkCreation.hook.ts"
          },
          {
            "type": "command",
            "command": "C:\\Users\\JOSE\\.claude\\hooks\\ExplicitRatingCapture.hook.ts"
          },
          {
            "type": "command",
            "command": "C:\\Users\\JOSE\\.claude\\hooks\\ImplicitSentimentCapture.hook.ts"
          },
          {
            "type": "command",
            "command": "C:\\Users\\JOSE\\.claude\\hooks\\UpdateTabTitle.hook.ts"
          }
        ]
      }
    ],
    "SessionStart": [
      {
        "hooks": [
          {
            "type": "command",
            "command": "C:\\Users\\JOSE\\.claude\\hooks\\StartupGreeting.hook.ts"
          },
          {
            "type": "command",
            "command": "C:\\Users\\JOSE\\.claude\\hooks\\LoadContext.hook.ts"
          },
          {
            "type": "command",
            "command": "C:\\Users\\JOSE\\.claude\\hooks\\CheckVersion.hook.ts"
          }
        ]
      }
    ],
    "Stop": [
      {
        "hooks": [
          {
            "type": "command",
            "command": "C:\\Users\\JOSE\\.claude\\hooks\\StopOrchestrator.hook.ts"
          }
        ]
      }
    ],
    "SubagentStop": [
      {
        "hooks": [
          {
            "type": "command",
            "command": "C:\\Users\\JOSE\\.claude\\hooks\\AgentOutputCapture.hook.ts"
          }
        ]
      }
    ]
  },
  "statusLine": {
    "type": "command",
    "command": "C:\\Users\\JOSE\\.claude\\statusline-command.ps1"
  },
  "alwaysThinkingEnabled": true,
  "platform": "win32",
  "installDate": "2026-02-10T12:21:50.885Z",
  "_docs": {
    "_overview": "PAI v2.5 settings. Run install wizard to customize.",
    "_sections": {
      "contextFiles": "Files loaded at session start. Defaults load SKILL.md, AI Steering Rules, and DA Identity.",
      "daidentity": "AI identity (name, voice)",
      "principal": "Your identity",
      "permissions": "Tool permissions",
      "hooks": "Lifecycle event hooks"
    }
  },
  "max_tokens": 4096
}

